import { StrictMode } from 'react';
import { createRoot } from 'react-dom/client';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import App from './App';
import ThemeProvider from './theme/ThemeProvider';

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5, // 5 minutes
      refetchOnWindowFocus: false,
    },
  },
});

const container = document.getElementById('root');
if (!container) {
  throw new Error('Root container not found');
}

createRoot(container).render(
  <StrictMode>
    <QueryClientProvider client={queryClient}>
      <ThemeProvider>
        <App />
      </ThemeProvider>
    </QueryClientProvider>
  </StrictMode>
);

import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';

/**
 * Root application component.
 * Will be extended with PixiJS canvas and React overlays.
 */
export default function App() {
  return (
    <Box
      sx={{
        width: '100vw',
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        bgcolor: 'background.default',
      }}
    >
      {/* Header - will be replaced by proper toolbar */}
      <Box
        component="header"
        sx={{
          p: 2,
          borderBottom: 1,
          borderColor: 'divider',
          bgcolor: 'background.paper',
        }}
      >
        <Typography variant="h5" component="h1">
          MMS Fractal Planner
        </Typography>
        <Typography variant="body2" color="text.secondary">
          Rolling Stock Maintenance Scheduler - 128 trains × 12 years
        </Typography>
      </Box>

      {/* Main canvas area - PixiJS will mount here */}
      <Box
        sx={{
          flex: 1,
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        <Box
          sx={{
            position: 'absolute',
            inset: 0,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: 'text.disabled',
          }}
        >
          <Typography variant="h6">
            PixiJS Canvas will render here
          </Typography>
        </Box>
      </Box>
    </Box>
  );
}

