import { createStore } from 'zustand/vanilla';
import { useStore } from 'zustand';

/**
 * Viewport state for canvas rendering.
 * Uses Zustand vanilla store for direct subscription without React re-renders.
 *
 * Coordinate system:
 * x_viewport = (t_unix - t_origin) * scale + offset
 */
export interface ViewportState {
  /** Pixels per millisecond */
  scale: number;
  /** Viewport offset in pixels (virtual scroll position) */
  offsetX: number;
  offsetY: number;
  /** Origin timestamp (start of timeline) */
  originTime: number;
  /** Viewport dimensions */
  width: number;
  height: number;
  /** Current Level of Detail (0=heatmap, 1=bars, 2=capsules) */
  lod: 0 | 1 | 2;
}

export interface ViewportActions {
  setScale: (scale: number) => void;
  setOffset: (x: number, y: number) => void;
  pan: (deltaX: number, deltaY: number) => void;
  zoom: (factor: number, centerX: number, centerY: number) => void;
  setDimensions: (width: number, height: number) => void;
  setLod: (lod: 0 | 1 | 2) => void;
}

const INITIAL_SCALE = 0.00001; // px/ms (approximately 36px per hour)
const MIN_SCALE = 0.0000001; // Very zoomed out (years visible)
const MAX_SCALE = 0.001; // Very zoomed in (seconds visible)

/** LOD thresholds with hysteresis (px per hour) */
const LOD_THRESHOLDS = {
  heatmapToBarEnter: 0.1,
  heatmapToBarExit: 0.15,
  barToCapsuleEnter: 20,
  barToCapsuleExit: 15,
} as const;

function calculateLod(scale: number, currentLod: 0 | 1 | 2): 0 | 1 | 2 {
  const pxPerHour = scale * 3600000; // ms per hour

  if (currentLod === 0) {
    if (pxPerHour > LOD_THRESHOLDS.heatmapToBarExit) return 1;
    return 0;
  }

  if (currentLod === 1) {
    if (pxPerHour < LOD_THRESHOLDS.heatmapToBarEnter) return 0;
    if (pxPerHour > LOD_THRESHOLDS.barToCapsuleEnter) return 2;
    return 1;
  }

  // currentLod === 2
  if (pxPerHour < LOD_THRESHOLDS.barToCapsuleExit) return 1;
  return 2;
}

export const viewportStore = createStore<ViewportState & ViewportActions>((set, get) => ({
  scale: INITIAL_SCALE,
  offsetX: 0,
  offsetY: 0,
  originTime: Date.now(),
  width: 0,
  height: 0,
  lod: 1,

  setScale: (scale: number) => {
    const clampedScale = Math.max(MIN_SCALE, Math.min(MAX_SCALE, scale));
    const currentLod = get().lod;
    set({
      scale: clampedScale,
      lod: calculateLod(clampedScale, currentLod),
    });
  },

  setOffset: (x: number, y: number) => {
    set({ offsetX: x, offsetY: y });
  },

  pan: (deltaX: number, deltaY: number) => {
    const { offsetX, offsetY } = get();
    set({ offsetX: offsetX + deltaX, offsetY: offsetY + deltaY });
  },

  zoom: (factor: number, centerX: number, centerY: number) => {
    const { scale, offsetX } = get();
    const newScale = Math.max(MIN_SCALE, Math.min(MAX_SCALE, scale * factor));

    // Adjust offset to keep center point stationary
    const newOffsetX = centerX - (centerX - offsetX) * (newScale / scale);

    const currentLod = get().lod;
    set({
      scale: newScale,
      offsetX: newOffsetX,
      lod: calculateLod(newScale, currentLod),
    });
  },

  setDimensions: (width: number, height: number) => {
    set({ width, height });
  },

  setLod: (lod: 0 | 1 | 2) => {
    set({ lod });
  },
}));

/** React hook for viewport state (triggers re-render) */
export function useViewport<T>(selector: (state: ViewportState & ViewportActions) => T): T {
  return useStore(viewportStore, selector);
}

/** Direct access for non-React contexts (PixiJS render loop) */
export const getViewportState = viewportStore.getState;
export const subscribeViewport = viewportStore.subscribe;

import { createStore } from 'zustand/vanilla';
import { useStore } from 'zustand';

/**
 * Maintenance block types (stored as Uint8 enum).
 */
export const BlockType = {
  PM: 0,          // Preventive Maintenance
  OVERHAUL: 1,    // Major overhaul
  INSPECTION: 2,  // Regular inspection
  REPAIR: 3,      // Unplanned repair
  CLEANING: 4,    // Cleaning/detailing
} as const;

export type BlockTypeValue = typeof BlockType[keyof typeof BlockType];

/**
 * Structure of Arrays (SoA) for high-performance schedule data.
 * Pre-allocated TypedArrays for cache-friendly iteration.
 */
export interface ScheduleArrays {
  /** Capacity of pre-allocated arrays */
  capacity: number;
  /** Current number of active blocks */
  count: number;

  /** Start time in milliseconds (epoch) */
  startTimes: Float64Array;
  /** End time in milliseconds (epoch) */
  endTimes: Float64Array;
  /** Train ID (index into train lookup table) */
  trainIds: Int32Array;
  /** Block type (see BlockType enum) */
  types: Uint8Array;
  /** Track/bay ID for workshop assignment */
  trackIds: Int16Array;
  /** Status flags: bit 0 = selected, bit 1 = dragging, bit 2 = conflict */
  flags: Uint8Array;
}

export interface SimulationState {
  schedule: ScheduleArrays;
  /** Map of train index -> train metadata */
  trainLookup: Map<number, { id: string; name: string; fleet: string }>;
  /** Set of currently selected block indices */
  selectedBlocks: Set<number>;
  /** Index of block being dragged, or -1 */
  draggingBlock: number;
}

export interface SimulationActions {
  /** Initialize schedule arrays with capacity */
  initializeSchedule: (capacity: number) => void;
  /** Add a schedule block, returns index */
  addBlock: (
    startTime: number,
    endTime: number,
    trainId: number,
    type: BlockTypeValue,
    trackId: number
  ) => number;
  /** Update block times (for drag operations) */
  updateBlockTimes: (index: number, startTime: number, endTime: number) => void;
  /** Select/deselect a block */
  toggleBlockSelection: (index: number) => void;
  /** Clear all selections */
  clearSelection: () => void;
  /** Start dragging a block */
  startDrag: (index: number) => void;
  /** Stop dragging */
  stopDrag: () => void;
}

const DEFAULT_CAPACITY = 100000;

function createEmptySchedule(capacity: number): ScheduleArrays {
  return {
    capacity,
    count: 0,
    startTimes: new Float64Array(capacity),
    endTimes: new Float64Array(capacity),
    trainIds: new Int32Array(capacity),
    types: new Uint8Array(capacity),
    trackIds: new Int16Array(capacity),
    flags: new Uint8Array(capacity),
  };
}

export const simulationStore = createStore<SimulationState & SimulationActions>((set, get) => ({
  schedule: createEmptySchedule(DEFAULT_CAPACITY),
  trainLookup: new Map(),
  selectedBlocks: new Set(),
  draggingBlock: -1,

  initializeSchedule: (capacity: number) => {
    set({ schedule: createEmptySchedule(capacity) });
  },

  addBlock: (startTime, endTime, trainId, type, trackId) => {
    const { schedule } = get();
    const index = schedule.count;

    if (index >= schedule.capacity) {
      console.warn('Schedule capacity exceeded');
      return -1;
    }

    schedule.startTimes[index] = startTime;
    schedule.endTimes[index] = endTime;
    schedule.trainIds[index] = trainId;
    schedule.types[index] = type;
    schedule.trackIds[index] = trackId;
    schedule.flags[index] = 0;

    set({ schedule: { ...schedule, count: index + 1 } });
    return index;
  },

  updateBlockTimes: (index: number, startTime: number, endTime: number) => {
    const { schedule } = get();
    if (index < 0 || index >= schedule.count) return;

    schedule.startTimes[index] = startTime;
    schedule.endTimes[index] = endTime;
    // Trigger update without reallocating arrays
    set({ schedule: { ...schedule } });
  },

  toggleBlockSelection: (index: number) => {
    const { selectedBlocks, schedule } = get();
    const newSelection = new Set(selectedBlocks);

    if (newSelection.has(index)) {
      newSelection.delete(index);
      schedule.flags[index] &= ~1; // Clear selected bit
    } else {
      newSelection.add(index);
      schedule.flags[index] |= 1; // Set selected bit
    }

    set({ selectedBlocks: newSelection });
  },

  clearSelection: () => {
    const { selectedBlocks, schedule } = get();
    for (const index of selectedBlocks) {
      schedule.flags[index] &= ~1;
    }
    set({ selectedBlocks: new Set() });
  },

  startDrag: (index: number) => {
    const { schedule } = get();
    if (index >= 0 && index < schedule.count) {
      schedule.flags[index] |= 2; // Set dragging bit
      set({ draggingBlock: index });
    }
  },

  stopDrag: () => {
    const { draggingBlock, schedule } = get();
    if (draggingBlock >= 0) {
      schedule.flags[draggingBlock] &= ~2; // Clear dragging bit
    }
    set({ draggingBlock: -1 });
  },
}));

/** React hook for simulation state */
export function useSimulation<T>(selector: (state: SimulationState & SimulationActions) => T): T {
  return useStore(simulationStore, selector);
}

/** Direct access for non-React contexts */
export const getSimulationState = simulationStore.getState;
export const subscribeSimulation = simulationStore.subscribe;

export {
  viewportStore,
  useViewport,
  getViewportState,
  subscribeViewport,
  type ViewportState,
  type ViewportActions,
} from './viewportStore';

export {
  simulationStore,
  useSimulation,
  getSimulationState,
  subscribeSimulation,
  BlockType,
  type BlockTypeValue,
  type ScheduleArrays,
  type SimulationState,
  type SimulationActions,
} from './simulationStore';

