import seedrandom from 'seedrandom';
import { BlockType, type BlockTypeValue } from '../../engine/store/simulationStore';

/**
 * Maintenance type definitions matching DEMO_DATA.md
 */
export const MAINTENANCE_TYPES = {
  A: {
    id: 'A',
    level: 'A' as const,
    name: 'A-Check',
    intervalKm: 10_000,
    toleranceKm: 2_000,
    durationHours: 4,
    manHours: 8,
    requiredTracks: 1,
    estimatedCost: 2_500,
    blockType: BlockType.PM,
  },
  B: {
    id: 'B',
    level: 'B' as const,
    name: 'B-Check',
    intervalKm: 50_000,
    toleranceKm: 5_000,
    durationHours: 16,
    manHours: 32,
    requiredTracks: 1,
    estimatedCost: 8_500,
    blockType: BlockType.INSPECTION,
  },
  C: {
    id: 'C',
    level: 'C' as const,
    name: 'C-Check',
    intervalKm: 200_000,
    toleranceKm: 20_000,
    durationHours: 72,
    manHours: 160,
    requiredTracks: 1,
    estimatedCost: 45_000,
    blockType: BlockType.INSPECTION,
  },
  D: {
    id: 'D',
    level: 'D' as const,
    name: 'D-Overhaul',
    intervalKm: 800_000,
    toleranceKm: 50_000,
    durationHours: 480,
    manHours: 1_200,
    requiredTracks: 2,
    estimatedCost: 180_000,
    blockType: BlockType.OVERHAUL,
  },
} as const;

/**
 * Depot definitions matching DEMO_DATA.md
 */
export const DEPOTS = {
  RED: {
    id: 'depot-red',
    name: 'Al Rashidiya',
    trackCount: 5,
    weeklyManHours: 2_800,
    assetTypes: ['ALSTOM'],
  },
  GREEN: {
    id: 'depot-green',
    name: 'Jebel Ali',
    trackCount: 4,
    weeklyManHours: 2_400,
    assetTypes: ['KINKI'],
  },
} as const;

export interface Train {
  id: string;
  index: number;
  type: 'ALSTOM' | 'KINKI';
  carsCount: number;
  baseMileageKm: number;
  avgDailyMileageKm: number;
  depot: typeof DEPOTS.RED | typeof DEPOTS.GREEN;
}

export interface ScheduleBlock {
  index: number;
  trainIndex: number;
  startTime: number;
  endTime: number;
  type: BlockTypeValue;
  trackId: number;
